package main

import (
	"flag"
	"os"
	"time"

	"github.com/volcano-sh/agentcube/pkg/idlecleanup"
	"k8s.io/klog/v2"
	"k8s.io/client-go/kubernetes"
	"k8s.io/client-go/rest"
	ctrl "sigs.k8s.io/controller-runtime"
