package idlecleanup

import (
	"context"
	"fmt"
	"time"

	"k8s.io/apimachinery/pkg/api/errors"
	"k8s.io/apimachinery/pkg/labels"
	"k8s.io/client-go/kubernetes"
	"k8s.io/klog/v2"
	"sigs.k8s.io/controller-runtime/pkg/client"
	"sigs.k8s.io/controller-runtime/pkg/manager"
	"sigs.k8s.io/controller-runtime/pkg/reconcile"
	"sigs.k8s.io/controller-runtime/pkg/controller"
	"sigs.k8s.io/controller-runtime/pkg/handler"
	"sigs.k8s.io/controller-runtime/pkg/predicate"
	"sigs.k8s.io/controller-runtime/pkg/source"
	"sigs.k8s.io/controller-runtime/pkg/log"

	sandboxv1alpha1 "github.com/volcano-sh/agent-sandbox/api/v1alpha1"
)

const (
	LastActivityAnnotationKey = "last-activity-time"
	SessionExpirationTimeout   = 15 * time.Minute
)

var (
	log_ = log.Log.WithName("idlecleanup")
)

type Reconciler struct {
	kubeClient        kubernetes.Interface
	client           client.Client
	namespace        string
	expirationTimeout time.Duration
	syncInterval    time.Duration
}

func NewReconciler(kubeClient kubernetes.Interface, namespace string, expirationTimeout, syncInterval time.Duration) *Reconciler {
	return &Reconciler{
		kubeClient:        kubeClient,
		namespace:        namespace,
		expirationTimeout: expirationTimeout,
		syncInterval:    syncInterval,
	}
}

func (r *Reconciler) SetupWithManager(mgr manager.Manager) error {
	r.client = mgr.GetClient()

	_, err := controller.New("idlecleanup-controller", mgr, controller.Options{
		Reconciler: r,
	})
	if err != nil {
		return err
	}

	src := source.NewKindWithCache(&sandboxv1alpha1.Sandbox{}, mgr.GetCache())
	hdler := handler.EnqueueRequestsFromMapFunc(r.enqueueRequests)

	pred := predicate.Funcs{
		CreateFunc: func(e event.CreateEvent) bool { return true },
		DeleteFunc: func(e event.DeleteEvent) bool { return true },
		UpdateFunc: func(e event.UpdateEvent) bool { return true },
		GenericFunc: func(e event.GenericEvent) bool { return true },
	}

	if err := mgr.GetCache().IndexField(context.Background(), &sandboxv1alpha1.Sandbox{}, ".spec.state", r.indexStateField); err != nil {
		return err
	}

	return mgr.Add(controller.New("idlecleanup-controller", mgr, controller.Options{
		Reconciler: r,
	}))
}

func (r *Reconciler) indexStateField(o client.Object) []string {
	sb := o.(*sandboxv1alpha1.Sandbox)
	return []string{sb.Spec.State}
}

func (r *Reconciler) enqueueRequests(_ context.Context, o handler.MapObject) []reconcile.Request {
	return []reconcile.Request{
		{
			NamespacedName: client.ObjectKeyFromObject(o.Object),
		},
	}
}

func (r *Reconciler) Reconcile(ctx context.Context, req reconcile.Request) (reconcile.Result, error) {
	startTime := time.Now()
	defer func() {
		duration := time.Since(startTime)
		klog.V(4).Infof("Reconciliation completed in %v", duration)
	}()

	namespace := req.Namespace
	if r.namespace != "" {
		namespace = r.namespace
	}

	sandbox := &sandboxv1alpha1.Sandbox{}
	err := r.client.Get(ctx, req.NamespacedName, sandbox)
	if err != nil {
		if errors.IsNotFound(err) {
			klog.V(4).Infof("Sandbox %s not found, skipping", req.NamespacedName)
			return reconcile.Result{}, nil
		}
		klog.Errorf("Failed to get Sandbox %s: %v", req.NamespacedName, err)
		return reconcile.Result{}, err
	}

	lastActivityStr, ok := sandbox.Annotations[LastActivityAnnotationKey]
	if !ok {
		klog.V(4).Infof("Sandbox %s has no last-activity-time annotation, skipping", req.NamespacedName)
		return reconcile.Result{RequeueAfter: r.syncInterval}, nil
	}

	lastActivity, err := time.Parse(time.RFC3339, lastActivityStr)
	if err != nil {
		klog.Errorf("Failed to parse last-activity-time for Sandbox %s: %v", req.NamespacedName, err)
		return reconcile.Result{RequeueAfter: r.syncInterval}, nil
	}

	expirationTime := lastActivity.Add(r.expirationTimeout)
	now := time.Now()

	if now.After(expirationTime) {
		klog.Infof("Deleting expired Sandbox %s (last activity: %v, expiration: %v)",
			req.NamespacedName, lastActivity, expirationTime)

		policy := client.DeletePropagationForeground
		if err := r.client.Delete(ctx, sandbox, &client.DeleteOptions{PropagationPolicy: &policy}); err != nil {
			if errors.IsNotFound(err) {
				klog.V(4).Infof("Sandbox %s already deleted", req.NamespacedName)
				return reconcile.Result{}, nil
			}
			klog.Errorf("Failed to delete Sandbox %s: %v", req.NamespacedName, err)
			return reconcile.Result{}, err
		}

		klog.Infof("Successfully deleted expired Sandbox %s", req.NamespacedName)
		return reconcile.Result{}, nil
	}

	requeueTime := expirationTime.Sub(now)
	if requeueTime < time.Second {
		requeueTime = time.Second
	}

	klog.V(4).Infof("Sandbox %s not yet expired (expires in %v)", req.NamespacedName, requeueTime)
	return reconcile.Result{RequeueAfter: requeueTime}, nil
}

func (r *Reconciler) ReconcileExpiredSandboxes(ctx context.Context) error {
	namespace := r.namespace
	if namespace == "" {
		namespace = metav1.NamespaceAll
	}

	listOpts := &client.ListOptions{
		Namespace:     namespace,
		LabelSelector: labels.Everything(),
	}

	sandboxList := &sandboxv1alpha1.SandboxList{}
	if err := r.client.List(ctx, sandboxList, listOpts); err != nil {
		return fmt.Errorf("failed to list sandboxes: %w", err)
	}

	now := time.Now()
	deletedCount := 0

	for i := range sandboxList.Items {
		sb := &sandboxList.Items[i]

		lastActivityStr, ok := sb.Annotations[LastActivityAnnotationKey]
		if !ok {
			continue
		}

		lastActivity, err := time.Parse(time.RFC3339, lastActivityStr)
		if err != nil {
			continue
		}

		expirationTime := lastActivity.Add(r.expirationTimeout)
		if now.After(expirationTime) {
			klog.Infof("Cleaning up expired sandbox %s/%s", sb.Namespace, sb.Name)

			policy := client.DeletePropagationForeground
			if err := r.client.Delete(ctx, sb, &client.DeleteOptions{PropagationPolicy: &policy}); err != nil {
				if !errors.IsNotFound(err) {
					klog.Errorf("Failed to delete sandbox %s/%s: %v", sb.Namespace, sb.Name, err)
				}
				continue
			}
			deletedCount++
		}
	}

	klog.V(2).Infof("Cleaned up %d expired sandboxes in namespace %s", deletedCount, namespace)
	return nil
}

