package store

import (
	"context"
	"time"

	"github.com/volcano-sh/agentcube/pkg/common/types"
)

type SessionStore interface {
	CreateSession(ctx context.Context, session *Session) error
	GetSession(ctx context.Context, sessionID string) (*Session, error)
	UpdateSession(ctx context.Context, session *Session) error
	DeleteSession(ctx context.Context, sessionID string) error
	ListSessions(ctx context.Context, namespace string) ([]*Session, error)
	UpdateLastActivity(ctx context.Context, sessionID string, t time.Time) error
	Ping(ctx context.Context) error
	Close() error
}

type Session struct {
	ID           string            `json:"session_id"`
	Namespace    string            `json:"namespace"`
	Name         string            `json:"name"`
	Kind         string            `json:"kind"`
	SandboxID    string            `json:"sandbox_id"`
	EntryPoints  []EntryPoint      `json:"entry_points"`
	CreatedAt    time.Time         `json:"created_at"`
	LastActivity time.Time         `json:"last_activity_time"`
	ExpiresAt    time.Time         `json:"expires_at"`
	Metadata     map[string]string `json:"metadata"`
}

type EntryPoint struct {
	Type    string `json:"type"`
	URL     string `json:"url"`
	ProxyURL string `json:"proxy_url"`
}

func SessionFromSandboxInfo(info *types.SandboxInfo) *Session {
	return &Session{
		ID:           info.SessionID,
		Namespace:    info.Namespace,
		Name:         info.Name,
		Kind:         info.Kind,
		SandboxID:    info.SandboxID,
		EntryPoints:  convertEntryPoints(info.EntryPoints),
		CreatedAt:    info.CreatedAt,
		LastActivity: info.LastActivityTime,
		ExpiresAt:    info.ExpiresAt,
		Metadata:     info.Metadata,
	}
}

func (s *Session) ToSandboxInfo() *types.SandboxInfo {
	return &types.SandboxInfo{
		SessionID:        s.ID,
		Namespace:        s.Namespace,
		Name:             s.Name,
		Kind:             s.Kind,
		SandboxID:        s.SandboxID,
		EntryPoints:      convertBackEntryPoints(s.EntryPoints),
		CreatedAt:        s.CreatedAt,
		LastActivityTime: s.LastActivity,
		ExpiresAt:        s.ExpiresAt,
		Metadata:         s.Metadata,
	}
}

func convertEntryPoints(eps []types.EntryPoint) []EntryPoint {
	result := make([]EntryPoint, len(eps))
	for i, ep := range eps {
		result[i] = EntryPoint{
			Type:     ep.Type,
			URL:      ep.URL,
			ProxyURL: ep.ProxyURL,
		}
	}
	return result
}

func convertBackEntryPoints(eps []EntryPoint) []types.EntryPoint {
	result := make([]types.EntryPoint, len(eps))
	for i, ep := range eps {
		result[i] = types.EntryPoint{
			Type:     ep.Type,
			URL:      ep.URL,
			ProxyURL: ep.ProxyURL,
		}
	}
	return result
}

package redis

import (
	"context"
	"encoding/json"
	"fmt"
	"time"

	"github.com/redis/go-redis/v9"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/store"
)

type RedisSessionStore struct {
	client *redis.Client
	ttl    time.Duration
}

func NewRedisSessionStore(addr string, password string, db int, ttl time.Duration) (*RedisSessionStore, error) {
	client := redis.NewClient(&redis.Options{
		Addr:     addr,
		Password: password,
		DB:       db,
	})

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	if err := client.Ping(ctx).Err(); err != nil {
		return nil, fmt.Errorf("failed to connect to redis: %w", err)
	}

	klog.Infof("Connected to Redis at %s", addr)

	return &RedisSessionStore{
		client: client,
		ttl:    ttl,
	}, nil
}

func (r *RedisSessionStore) CreateSession(ctx context.Context, session *store.Session) error {
	key := fmt.Sprintf("session:%s", session.ID)

	if session.CreatedAt.IsZero() {
		session.CreatedAt = time.Now()
	}
	if session.LastActivity.IsZero() {
		session.LastActivity = session.CreatedAt
	}
	if session.ExpiresAt.IsZero() {
		session.ExpiresAt = session.LastActivity.Add(r.ttl)
	}

	data, err := json.Marshal(session)
	if err != nil {
		return fmt.Errorf("failed to marshal session: %w", err)
	}

	err = r.client.Set(ctx, key, data, r.ttl).Err()
	if err != nil {
		return fmt.Errorf("failed to create session: %w", err)
	}

	klog.V(4).Infof("Created session %s with TTL %v", session.ID, r.ttl)
	return nil
}

func (r *RedisSessionStore) GetSession(ctx context.Context, sessionID string) (*store.Session, error) {
	key := fmt.Sprintf("session:%s", sessionID)

	data, err := r.client.Get(ctx, key).Bytes()
	if err == redis.Nil {
		return nil, fmt.Errorf("session %s not found", sessionID)
	}
	if err != nil {
		return nil, fmt.Errorf("failed to get session: %w", err)
	}

	var session store.Session
	if err := json.Unmarshal(data, &session); err != nil {
		return nil, fmt.Errorf("failed to unmarshal session: %w", err)
	}

	return &session, nil
}

func (r *RedisSessionStore) UpdateSession(ctx context.Context, session *store.Session) error {
	key := fmt.Sprintf("session:%s", session.ID)

	existing, err := r.GetSession(ctx, session.ID)
	if err != nil {
		return err
	}

	session.CreatedAt = existing.CreatedAt
	session.LastActivity = time.Now()

	data, err := json.Marshal(session)
	if err != nil {
		return fmt.Errorf("failed to marshal session: %w", err)
	}

	ttl := r.ttl
	if !session.ExpiresAt.IsZero() {
		remaining := time.Until(session.ExpiresAt)
		if remaining > 0 && remaining < ttl {
			ttl = remaining
		}
	}

	err = r.client.Set(ctx, key, data, ttl).Err()
	if err != nil {
		return fmt.Errorf("failed to update session: %w", err)
	}

	klog.V(4).Infof("Updated session %s", session.ID)
	return nil
}

func (r *RedisSessionStore) DeleteSession(ctx context.Context, sessionID string) error {
	key := fmt.Sprintf("session:%s", sessionID)

	err := r.client.Del(ctx, key).Err()
	if err != nil {
		return fmt.Errorf("failed to delete session: %w", err)
	}

	klog.V(4).Infof("Deleted session %s", sessionID)
	return nil
}

func (r *RedisSessionStore) ListSessions(ctx context.Context, namespace string) ([]*store.Session, error) {
	pattern := "session:*"
	if namespace != "" {
		pattern = fmt.Sprintf("session:%s:*", namespace)
	}

	keys, err := r.client.Keys(ctx, pattern).Result()
	if err != nil {
		return nil, fmt.Errorf("failed to list session keys: %w", err)
	}

	sessions := make([]*store.Session, 0, len(keys))
	for _, key := range keys {
		data, err := r.client.Get(ctx, key).Bytes()
		if err != nil {
			klog.Warningf("Failed to get session %s: %v", key, err)
			continue
		}

		var session store.Session
		if err := json.Unmarshal(data, &session); err != nil {
			klog.Warningf("Failed to unmarshal session %s: %v", key, err)
			continue
		}

		sessions = append(sessions, &session)
	}

	return sessions, nil
}

func (r *RedisSessionStore) UpdateLastActivity(ctx context.Context, sessionID string, t time.Time) error {
	key := fmt.Sprintf("session:%s", sessionID)

	session, err := r.GetSession(ctx, sessionID)
	if err != nil {
		return err
	}

	session.LastActivity = t

	data, err := json.Marshal(session)
	if err != nil {
		return fmt.Errorf("failed to marshal session: %w", err)
	}

	ttl := r.ttl
	if !session.ExpiresAt.IsZero() {
		remaining := time.Until(session.ExpiresAt)
		if remaining > 0 && remaining < ttl {
			ttl = remaining
		}
	}

	return r.client.Set(ctx, key, data, ttl).Err()
}

func (r *RedisSessionStore) Ping(ctx context.Context) error {
	return r.client.Ping(ctx).Err()
}

func (r *RedisSessionStore) Close() error {
	return r.client.Close()
}

