		sessionsDeleted: promauto.NewCounter(prometheus.CounterOpts{
			Name: "agentcube_sessions_deleted_total",
			Help: "Total number of sessions deleted",
		}),
		operationLatency: promauto.NewHistogramVec(prometheus.HistogramOpts{
			Name:    "agentcube_store_operation_duration_seconds",
			Help:    "Latency of store operations in seconds",
			Buckets: prometheus.DefBuckets,
		}, []string{"operation", "status"}),
	}
}

func (m *StoreMetrics) RecordActiveSessions(count int) {
	m.sessionsActive.Set(float64(count))
}

