func (m *StoreMetrics) IncrementSessionsDeleted() {
	m.sessionsDeleted.Inc()
}

func (m *StoreMetrics) RecordOperation(operation string, duration time.Duration, status string) {
	m.operationLatency.WithLabelValues(operation, status).Observe(duration.Seconds())
}

package workloadmanager

import (
	"context"
	"fmt"
	"sync"
	"time"

	corev1 "k8s.io/api/core/v1"
	"k8s.io/apimachinery/pkg/api/errors"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/client-go/kubernetes"
	"k8s.io/klog/v2"

	sandboxv1alpha1 "github.com/volcano-sh/agent-sandbox/api/v1alpha1"
)

type WarmPoolManager struct {
	client    kubernetes.Interface
	poolSize  int
	namespace string
	template  *sandboxv1alpha1.Sandbox
	mu       sync.Mutex
	pool     []*sandboxv1alpha1.Sandbox
}

func NewWarmPoolManager(client kubernetes.Interface, namespace string, poolSize int, template *sandboxv1alpha1.Sandbox) *WarmPoolManager {
	return &WarmPoolManager{
		client:    client,
		namespace: namespace,
		poolSize:  poolSize,
		template:  template,
		pool:      make([]*sandboxv1alpha1.Sandbox, 0),
	}
}

func (m *WarmPoolManager) GetWarmSandbox(ctx context.Context) (*sandboxv1alpha1.Sandbox, error) {
	m.mu.Lock()
	defer m.mu.Unlock()

	if len(m.pool) > 0 {
		sandbox := m.pool[len(m.pool)-1]
		m.pool = m.pool[:len(m.pool)-1]
		klog.V(4).Infof("Retrieved warm sandbox %s from pool (remaining: %d)", sandbox.Name, len(m.pool))
		return sandbox, nil
	}

	klog.V(4).Infof("No warm sandboxes available, creating new one")
	return m.createNewSandbox(ctx)
}

func (m *WarmPoolManager) ReturnToPool(ctx context.Context, sandbox *sandboxv1alpha1.Sandbox) error {
	m.mu.Lock()
	defer m.mu.Unlock()

	if len(m.pool) >= m.poolSize {
		klog.V(4).Infof("Pool full, deleting sandbox %s", sandbox.Name)
		return m.deleteSandbox(ctx, sandbox.Name)
	}

	m.pool = append(m.pool, sandbox)
	klog.V(4).Infof("Returned sandbox %s to pool (pool size: %d)", sandbox.Name, len(m.pool))
	return nil
}

func (m *WarmPoolManager) MaintainPool(ctx context.Context) error {
	m.mu.Lock()
	defer m.mu.Unlock()

	targetCount := m.poolSize - len(m.pool)
	if targetCount <= 0 {
		return nil
	}

	klog.V(2).Infof("Maintaining warm pool: current=%d, target=%d", len(m.pool), m.poolSize)

	for i := 0; i < targetCount; i++ {
		sandbox, err := m.createNewSandbox(ctx)
		if err != nil {
			klog.Errorf("Failed to create warm sandbox: %v", err)
			continue
		}
		m.pool = append(m.pool, sandbox)
	}

	return nil
}

func (m *WarmPoolManager) createNewSandbox(ctx context.Context) (*sandboxv1alpha1.Sandbox, error) {
	if m.template == nil {
		return nil, fmt.Errorf("sandbox template not configured")
	}

	name := fmt.Sprintf("warm-%s-%d", m.template.Name, time.Now().UnixNano())

	sandbox := &sandboxv1alpha1.Sandbox{
		ObjectMeta: metav1.ObjectMeta{
			Name:      name,
			Namespace: m.namespace,
			Labels:    m.template.Labels,
		},
		Spec: m.template.Spec,
	}

	created, err := m.client.SandboxV1alpha1().Sandboxes(m.namespace).Create(ctx, sandbox, metav1.CreateOptions{})
	if err != nil {
		return nil, fmt.Errorf("failed to create sandbox: %w", err)
	}

	klog.V(2).Infof("Created warm sandbox %s", name)
	return created, nil
}

func (m *WarmPoolManager) deleteSandbox(ctx context.Context, name string) error {
	err := m.client.SandboxV1alpha1().Sandboxes(m.namespace).Delete(ctx, name, metav1.DeleteOptions{})
	if err != nil && !errors.IsNotFound(err) {
		return fmt.Errorf("failed to delete sandbox: %w", err)
	}
	return nil
}

