	ActiveCount int
}

func NewScalingPolicy() *ScalingPolicy {
	return &ScalingPolicy{
		MinReplicas:    1,
		MaxReplicas:    10,
		TargetCPU:      70,
		TargetMemory:   80,
		ScaleUpDelay:   1 * time.Minute,
		ScaleDownDelay: 5 * time.Minute,
	}
}

func (p *ScalingPolicy) CalculateReplicas(current int, metrics *ResourceMetrics) int {
	if metrics == nil {
		return current
	}

	desired := current

	if metrics.CPUUsage > float64(p.TargetCPU) || metrics.MemoryUsage > float64(p.TargetMemory) {
		desired = current + 1
	} else if metrics.CPUUsage < 30 && metrics.MemoryUsage < 40 && metrics.ActiveCount > p.MinReplicas {
		desired = current - 1
	}

	if desired < p.MinReplicas {
		desired = p.MinReplicas
	}
	if desired > p.MaxReplicas {
		desired = p.MaxReplicas
	}

	return desired
}

type SandboxTemplate struct {
